def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    positive_bins = bins[bins > 0]
    avg_capacity = np.mean(positive_bins) if positive_bins.size > 0 else 1
    variance = np.var(positive_bins) if positive_bins.size > 0 else 0.1
    std_dev = np.std(positive_bins) if positive_bins.size > 0 else 0.5
    median_capacity = np.median(positive_bins) if positive_bins.size > 0 else 1
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0 or capacity < item:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio == 1:
            score = 0
        elif ratio > 0.9:
            score = (1 - ratio)**4 * 1.5 + 0.3
        elif 0.7 < ratio <= 0.9:
            score = np.exp(-ratio * 20) + 0.1
        elif 0.4 < ratio <= 0.7:
            score = sum([((-1)**(k+1)) * (ratio**(k+3)) / (k*1.05) for k in range(1, 10)])
            score = abs(score) + 0.12
        else:
            score = 0
            for p in range(1, 15):
                weight = np.exp(-p/5) / (p ** 1.1)
                score += ((-1)**p) * (ratio ** (p+2)) * weight
            score = abs(score) + 0.15
        neighbors_influence = 0.0
        neighbors_weights_sum = 0.0
        max_offset = min(10, n)
        for offset in range(1, max_offset):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff = abs(capacity - neighbor_capacity)
                    norm_diff = diff / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.8 + 0.5)
                    influence = norm_diff * weight
                    if neighbor_capacity > avg_capacity + std_dev * 1.5:
                        influence *= 1.25
                    elif neighbor_capacity < avg_capacity - std_dev:
                        influence *= 0.8
                    neighbors_influence += influence
                    neighbors_weights_sum += weight
        if neighbors_weights_sum > 0:
            neighbors_influence /= neighbors_weights_sum
        cap_factor = (capacity ** 0.65) + (median_capacity ** 0.35)
        if cap_factor == 0:
            cap_factor = 1
        penalty = 0
        if capacity < 1.5 * item:
            penalty = ((1.5 * item - capacity) ** 2) * 0.3
        if capacity > item * 3:
            penalty += 0.07
        if i % 5 == 0:
            score *= 0.85
            neighbors_influence *= 1.3
            penalty *= 1.05
        elif i % 3 == 0:
            score *= 1.15
            neighbors_influence *= 0.85
        elif i % 7 == 0:
            score *= 0.9
            neighbors_influence *= 1.1
            penalty *= 1.2
        else:
            score *= 1.0
        residual = capacity - item
        bonus = 0
        for power in range(1, 5):
            if residual > power * 5:
                bonus += np.log(residual / (power * 5)) / (power * 10)
            else:
                bonus -= (power * 0.02)
        priority = score + neighbors_influence / cap_factor + penalty - bonus
        if priority < 0:
            priority = 0
        if (i % 2 == 0) and (int(capacity) % 10 == 0):
            priority *= 0.92
        elif (i % 2 != 0) and (int(capacity) % 7 == 0):
            priority *= 1.07
        priorities[i] = priority
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return priorities
    max_finite = np.max(finite)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 7
    return priorities
